#include <iostream>

using namespace std;

struct Node {
    int val;
    Node *next, *prev;
    Node(int v) : val(v), next(nullptr), prev(nullptr) {}
};

class MyLinkedList {
public:
    Node *head, *tail;
    int size;

    MyLinkedList() : head(nullptr), tail(nullptr), size(0) {}

    Node* getNode(int index)
    {
        Node* cur = head;
        for (int i = 0; i < index; i++) cur = cur->next;
        return cur;
    }

    int get(int index)
    {
        if (index < 0 || index >= size) return -1;
        return getNode(index)->val;
    }

    void addAtHead(int val)
    {
        Node* node = new Node(val);
        node->next = head;
        if (head) head->prev = node;
        head = node;
        if (!tail) tail = node;
        size++;
    }

    void addAtTail(int val)
    {
        Node* node = new Node(val);
        node->prev = tail;
        if (tail) tail->next = node;
        tail = node;
        if (!head) head = node;
        size++;
    }

    void addAtIndex(int index, int val)
    {
        if (index <= 0) { addAtHead(val); return; }
        if (index == size) { addAtTail(val); return; }
        if (index > size) return;

        Node* next = getNode(index);
        Node* prev = next->prev;
        Node* node = new Node(val);

        node->prev = prev; node->next = next;
        prev->next = node; next->prev = node;
        size++;
    }

    void deleteAtIndex(int index)
    {
        if (index < 0 || index >= size) return;

        Node* target = getNode(index);
        if (target->prev) target->prev->next = target->next; else head = target->next;
        if (target->next) target->next->prev = target->prev; else tail = target->prev;

        delete target;
        size--;
    }
};

int main()
{
    MyLinkedList list;
    list.addAtHead(1);
    list.addAtTail(3);
    list.addAtIndex(1, 2);
    cout << list.get(1) << ", ";
    list.deleteAtIndex(1);
    cout << list.get(1) << endl;

    return 0;
}

